import React from "react";
import "../Home/Profile.css";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

export default function Resume() {
  return (
    <div>
      <h2 className="headMain">Resume</h2>
      <h3 className="Habout">WORK EXPERIENCE</h3>
      <div className="resume-container">
        <div>
          <h1>Restaurant Manager</h1>
          <h3>Frozen restaurant</h3>
          <ul>
            <li>Purchased adequate quantities of food, beverages, equipment and supplies. Led and directed team members on effective methods, operations and procedures. Promoted positive atmosphere and went above and
beyond to guarantee each customer received exceptional
food and service.</li>
          </ul>
        </div>
      </div>
    </div>
  );
}
